document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll("a");e.forEach(e=>{e.addEventListener("click",e=>{const t=e.currentTarget,n=location.origin;if(!t.href.startsWith(n)){e.preventDefault();const o=encodeURIComponent(t.href);location.href=`${n}/redirect/go/${o}`}})})});